INSERT INTO "public"."feedback" ("id", "candidate_id", "author_id", "overall_percent", "recommendation", "notes", "status", "created_at", "updated_at") VALUES
	('b382d284-0b9d-434a-b4d7-8525e4306d0d', '4129cc6b-c84d-4d8e-b924-91d5494845ab', 'e2cf3e7b-d16b-49c7-9a60-00e65ec3049e', 100, 'hire', 'Overall take: Positive signal on experience and attitude; I believe Ashish can do well in the next rounds. Today’s conversation showed strong infra breadth and customer-facing maturity, but it didn’t surface enough first-principles architecture depth (sizing, landing zones, K8s/IaC, DR/security) to make a final call. I recommend a focused internal technical deep-dive (second opinion) before we proceed to client rounds.
